from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a mean of transportation into a fluent sentence.
    """
    if not triples:
        return ""
    clauses = []
    for t in triples:
        subj = t.subject
        pred = t.predicate
        obj = t.object

        # Simple verb mapping for common predicates
        if pred == "location":
            clause = f"{subj} is located in {obj}"
        elif pred == "owner":
            clause = f"{subj} is owned by {obj}"
        elif pred == "builder":
            clause = f"{subj} was built by {obj}"
        elif pred == "manufacturer":
            clause = f"{subj} is manufactured by {obj}"
        elif pred == "operator":
            clause = f"{subj} is operated by {obj}"
        elif pred == "status":
            clause = f"{subj} is {obj.lower()}"
        else:
            # fallback: use predicate as a verb phrase
            clause = f"{subj} {pred} {obj}"
        clauses.append(clause)

    # Join clauses into a single, readable sentence
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    else:
        sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."
    return sentence

# EVOLVE-BLOCK-END

